sql:
SELECT GROUP_CONCAT(rm.model_parameters) AS avg_model_parameters, rm.strategy_id 
FROM risk_models rm
GROUP BY rm.strategy_id;

SELECT COUNT(*) AS TotalStrategies, strategy_name, investment_objective
FROM investment_strategies
GROUP BY strategy_name, investment_objective;

SELECT *
FROM investment_strategies
ORDER BY strategy_name ASC;

SELECT index_id
FROM index_returns
ORDER BY return_value DESC;

SELECT AVG(weightage) as average_weightage
FROM strategy_securities
WHERE strategy_id = 0;

SELECT date, return_value 
FROM security_returns 
WHERE security_id = 5;

SELECT date, SUM(mean_return) AS total_mean_return
FROM performance_data
GROUP BY date;

SELECT strategy_id 
FROM investment_strategies 
ORDER BY time_horizon DESC;

